import type { PointsConfig } from '@smartcart/shared-types';
import type { SessionItem } from '../entities/shopping-session.entity';
import type { IPointsCalculationStrategy } from './points-calculation-strategy.interface';

/**
 * SPEND_MULTIPLIER — `round(itemPrice * quantity * value)` (README §2.3).
 * `unitPrice` is carried on the in-memory SessionItem from the product at scan
 * time (the README data model does not persist price; see SessionItem).
 */
export class SpendMultiplierStrategy implements IPointsCalculationStrategy {
  readonly strategyType = 'SPEND_MULTIPLIER' as const;

  calculate(item: SessionItem, config: PointsConfig): number {
    if (config.type !== 'SPEND_MULTIPLIER') {
      throw new Error(
        'SpendMultiplierStrategy received a non-SPEND_MULTIPLIER config',
      );
    }
    return Math.round(item.unitPrice * item.quantity * config.value);
  }
}
